    public static void main(String[] args) {
        String[] input = {"hello", "world"};
        String[] encoded = malfunctioning_code(input);
        for (String str : encoded) {
            System.out.println(str);
        }
    }

    public static String[] malfunctioning_code(String[] s) {
        String[] encodedStrings = new String[s.length];
        for (int i = 0; i < s.length; i++) {
            encodedStrings[i] = encode_shift(s[i]);
        }
        return encodedStrings;
    }

    private static String encode_shift(String s) {
        StringBuilder encoded = new StringBuilder();
        for (char ch : s.toCharArray()) {
            char shiftedChar = (char) (((ch - 'a' + 5) % 26) + 'a');
            encoded.append(shiftedChar);
        }
        return encoded.toString();
    }
}
