public class CircleDrawer {
    public static void main(String[] args) {
        String input = "circle";
        List<Integer> result = draw_circle(input);
        System.out.println(result);
    }

    public static List<Integer> draw_circle(String shape) {
        List<Integer> circleCoordinates = new ArrayList<>();
        if (shape.equals("circle")) {
            for (int i = 0; i < 360; i += 10) {
                int x = (int) (Math.cos(Math.toRadians(i)) * 10); // Radius of 10
                int y = (int) (Math.sin(Math.toRadians(i)) * 10);
                circleCoordinates.add(x);
                circleCoordinates.add(y);
            }
        }
        return circleCoordinates;
    }
}
