#include <iostream>
#include <vector>
#include <string>

std::vector<int> calculate_factorial(const std::string& num_str) {
    int num = std::stoi(num_str);
    std::vector<int> factorial(1, 1); // Start with 1! = 1

    for (int i = 2; i <= num; ++i) {
        int carry = 0;
        for (size_t j = 0; j < factorial.size(); ++j) {
            int product = factorial[j] * i + carry;
            factorial[j] = product % 10; // Store the last digit
            carry = product / 10; // Carry the rest
        }
        while (carry) {
            factorial.push_back(carry % 10);
            carry /= 10;
        }
    }

    // Reverse the result to get the correct order
    std::reverse(factorial.begin(), factorial.end());
    return factorial;
}

int main() {
    std::string input = "5"; // Example input
    std::vector<int> result = calculate_factorial(input);

    for (int digit : result) {
        std::cout << digit;
    }
    std::cout << std::endl;

    return 0;
}
